#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define BS BLOCK_SIZE

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    const int lid = (int)get_local_id(0);

    if (lid == 0) {
        int i, j, k;

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                shadow[i * BS + j] = m[(offset + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = i; j < BS; j++) {
                float sum = shadow[i * BS + j];
                for (k = 0; k < i; k++) {
                    sum -= shadow[i * BS + k] * shadow[k * BS + j];
                }
                shadow[i * BS + j] = sum;
            }

            for (j = i + 1; j < BS; j++) {
                float sum = shadow[j * BS + i];
                for (k = 0; k < i; k++) {
                    sum -= shadow[j * BS + k] * shadow[k * BS + i];
                }
                shadow[j * BS + i] = sum / shadow[i * BS + i];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                m[(offset + i) * matrix_dim + (offset + j)] = shadow[i * BS + j];
            }
        }
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    const int lid = (int)get_local_id(0);
    const int chunk_idx = (int)get_group_id(0);

    if (lid == 0) {
        int i, j, k;
        const int j_global = offset + BS * (chunk_idx + 1);
        const int i_global = offset + BS * (chunk_idx + 1);

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                dia[i * BS + j] = m[(offset + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                peri_row[i * BS + j] = m[(offset + i) * matrix_dim + (j_global + j)];
            }
        }

        for (j = 0; j < BS; j++) {
            for (i = 0; i < BS; i++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += dia[i * BS + k] * peri_row[k * BS + j];
                }
                peri_row[i * BS + j] = peri_row[i * BS + j] - sum;
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                m[(offset + i) * matrix_dim + (j_global + j)] = peri_row[i * BS + j];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                peri_col[i * BS + j] = m[(i_global + i) * matrix_dim + (offset + j)];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                float sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += peri_col[i * BS + k] * dia[k * BS + j];
                }
                peri_col[i * BS + j] = (peri_col[i * BS + j] - sum) / dia[j * BS + j];
            }
        }

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                m[(i_global + i) * matrix_dim + (offset + j)] = peri_col[i * BS + j];
            }
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int j_global = offset + BS * (bx + 1);
    const int i_global = offset + BS * (by + 1);

    const int row = i_global + ty;
    const int col = j_global + tx;

    int k;
    float sum = 0.0f;

    for (k = 0; k < BS; k++) {
        sum += m[row * matrix_dim + (offset + k)] *
               m[(offset + k) * matrix_dim + col];
    }

    m[row * matrix_dim + col] -= sum;
}
